def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val graph = mutable.Map[Long, mutable.ListBuffer[(Long, Long, Long)]]()
    for (e <- edges) {
        val ui = e(0)
        val vi = e(1)
        val start = e(2)
        val end = e(3)
        if (!graph.contains(ui)) {
            graph(ui) = mutable.ListBuffer()
        }
        graph(ui) += ((vi, start, end))
    }

    val minTime = mutable.Map[Long, Long]()
    val heap = mutable.PriorityQueue[(Long, Long)]()(Ordering.by(-_._1))
    heap.enqueue((0L, 0L))

    while (heap.nonEmpty) {
        val (currentTime, node) = heap.dequeue()
        if (node == n - 1) {
            return currentTime
        }
        if (minTime.getOrElse(node, Long.MaxValue) < currentTime) {
            continue
        }
        if (graph.contains(node)) {
            for ((neighbor, start, end) <- graph(node)) {
                val earliestDeparture = math.max(currentTime, start)
                if (earliestDeparture <= end) {
                    val arrivalTime = earliestDeparture + 1
