import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val adj = mutable.Map[Long, mutable.ListBuffer[(Long, Long, Long)]]()
  edges.foreach { edge =>
    val ui = edge(0)
    val vi = edge(1)
    val start = edge(2)
    val end = edge(3)
    adj.getOrElseUpdate(ui, mutable.ListBuffer()) += ((vi, start, end))
  }

  val dist = mutable.Map[Long, Long]()
  val heap = mutable.PriorityQueue[(Long, Long)]()(Ordering.by(-_._2))

  dist(0) = 0
  heap.enqueue((0, 0))

  while (heap.nonEmpty) {
    val (u, currentTime) = heap.dequeue()
    if (u == n - 1) return currentTime
    if (currentTime > dist.getOrElse(u, Long.MaxValue)) continue

    adj.getOrElse(u, mutable.ListBuffer()).foreach { case (v, start, end) =>
      val arrivalTime = if (currentTime <= end) {
        if (currentTime >= start) currentTime + 1
        else start + 1
      } else Long.MaxValue

      if (arrivalTime < dist.getOrElse(v, Long.MaxValue)) {
        dist(v) = arrivalTime
        heap.enqueue((v, arrivalTime))
      }
    }
  }

  dist.getOrElse(n - 1, -1L)
}
